'use client';

import { useState } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import { testimonials } from '@/lib/data/clients';
import { ScrollReveal } from '@/components/ui/ScrollReveal';

export function TestimonialsSection() {
  const [active, setActive] = useState(0);
  const prefersReducedMotion = useReducedMotion();

  const t = testimonials[active];

  return (
    <section className="bg-black section-padding" aria-labelledby="testimonials-heading">
      <div className="container-site">
        <ScrollReveal>
          <h2 id="testimonials-heading" className="font-display text-display-md text-white uppercase mb-16">
            What Clients Say
          </h2>
        </ScrollReveal>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
          {/* Navigation */}
          <div className="flex flex-row lg:flex-col gap-4">
            {testimonials.map((item, i) => (
              <button
                key={i}
                onClick={() => setActive(i)}
                className={`text-left transition-colors duration-200 ${
                  active === i ? 'text-white' : 'text-white/30 hover:text-white/60'
                }`}
                aria-label={`Testimonial from ${item.author}`}
              >
                <span className="block font-body text-sm font-semibold">{item.author}</span>
                <span className="block font-body text-xs text-inherit opacity-70 mt-0.5">{item.company}</span>
                {active === i && (
                  <motion.div
                    layoutId="testimonial-indicator"
                    className="mt-2 h-px w-8 bg-[#0000FF]"
                  />
                )}
              </button>
            ))}
          </div>

          {/* Quote */}
          <div className="lg:col-span-2">
            <AnimatePresence mode="wait">
              <motion.blockquote
                key={active}
                initial={prefersReducedMotion ? {} : { opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={prefersReducedMotion ? {} : { opacity: 0, y: -16 }}
                transition={{ duration: 0.4, ease: 'easeOut' }}
                className="border-l-2 border-[#0000FF] pl-8"
              >
                <p className="font-body text-xl md:text-2xl text-white/80 leading-relaxed font-light italic">
                  &ldquo;{t.quote}&rdquo;
                </p>
                <footer className="mt-6">
                  <cite className="not-italic">
                    <span className="block font-body font-semibold text-white">{t.author}</span>
                    <span className="block font-body text-sm text-white/40 mt-0.5">
                      {t.role}, {t.company}
                    </span>
                  </cite>
                </footer>
              </motion.blockquote>
            </AnimatePresence>
          </div>
        </div>
      </div>
    </section>
  );
}
