'use client';

import { cn } from '@/lib/utils';
import Link from 'next/link';

interface ButtonProps {
  children: React.ReactNode;
  href?: string;
  onClick?: () => void;
  variant?: 'primary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  className?: string;
  external?: boolean;
  type?: 'button' | 'submit' | 'reset';
  disabled?: boolean;
}

const variants = {
  primary: 'bg-[#0000FF] text-white hover:bg-white hover:text-[#0000FF] border border-[#0000FF]',
  outline: 'bg-transparent text-white border border-white hover:bg-white hover:text-black',
  ghost:   'bg-transparent text-white hover:text-[#0000FF] border border-transparent',
};

const sizes = {
  sm: 'px-5 py-2.5 text-sm',
  md: 'px-8 py-4 text-base',
  lg: 'px-10 py-5 text-lg',
};

export function Button({
  children,
  href,
  onClick,
  variant = 'primary',
  size = 'md',
  className,
  external,
  type = 'button',
  disabled,
}: ButtonProps) {
  const base = cn(
    'inline-flex items-center gap-2 font-body font-semibold tracking-wide uppercase transition-all duration-300 ease-out',
    variants[variant],
    sizes[size],
    disabled && 'opacity-40 pointer-events-none',
    className,
  );

  if (href) {
    return external ? (
      <a href={href} target="_blank" rel="noopener noreferrer" className={base}>
        {children}
      </a>
    ) : (
      <Link href={href} className={base}>
        {children}
      </Link>
    );
  }

  return (
    <button type={type} onClick={onClick} disabled={disabled} className={base}>
      {children}
    </button>
  );
}
